-- =====================================================================
-- GITT - Esquema fisico Oracle
-- Sistema de Gestion de Inventario Tecnologico FISEI
-- Se ejecuta automaticamente la primera vez que arranca el contenedor.
-- =====================================================================
-- Notas de implementacion:
--  - gvenzl/oracle-xe ejecuta scripts como SYSDBA en CDB$ROOT, asi que
--    reconectamos al PDB XEPDB1 con el APP_USER ya creado por la imagen.
--  - PKs con GENERATED BY DEFAULT ON NULL AS IDENTITY: si la app inserta
--    NULL o no provee la columna, Oracle genera el siguiente valor.
--  - Campos auxiliares respecto al PDF (decisiones de implementacion):
--      ARTICULO.ACT_ART        soft-delete logico ('S'/'N')
--      NOTIFICACION.ID_USU_DEST  usuario destinatario de la notificacion

CONNECT GITT_SCHEMA/GittPass2024@//localhost:1521/XEPDB1

-- Tabla ROL
CREATE TABLE ROL (
    ID_ROL   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    NOM_ROL  VARCHAR(30) NOT NULL,
    DES_ROL  VARCHAR(120)
);

-- Tabla USUARIO
CREATE TABLE USUARIO (
    ID_USU   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    NOM_USU  VARCHAR(20) NOT NULL,
    APE_USU  VARCHAR(20) NOT NULL,
    COR_USU  VARCHAR(40) UNIQUE NOT NULL,
    CLA_USU  VARCHAR(100) NOT NULL,
    EST_USU  VARCHAR(15) NOT NULL,
    ID_ROL   NUMBER(10) NOT NULL,
    CONSTRAINT FK_USUARIO_ROL FOREIGN KEY (ID_ROL) REFERENCES ROL(ID_ROL)
);

-- Tabla DEPARTAMENTO
CREATE TABLE DEPARTAMENTO (
    ID_DEP   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    NOM_DEP  VARCHAR(40) NOT NULL,
    DES_DEP  VARCHAR(120)
);

-- Tabla UBICACION
CREATE TABLE UBICACION (
    ID_UBI   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    NOM_UBI  VARCHAR(40) NOT NULL,
    TIP_UBI  VARCHAR(20) NOT NULL,
    DES_UBI  VARCHAR(120),
    ID_DEP   NUMBER(10) NOT NULL,
    CONSTRAINT FK_UBICACION_DEPARTAMENTO FOREIGN KEY (ID_DEP) REFERENCES DEPARTAMENTO(ID_DEP)
);

-- Tabla CATEGORIA
CREATE TABLE CATEGORIA (
    ID_CAT   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    NOM_CAT  VARCHAR(25) NOT NULL,
    DES_CAT  VARCHAR(120)
);

-- Tabla ESTADO_ARTICULO
CREATE TABLE ESTADO_ARTICULO (
    ID_EST   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    NOM_EST  VARCHAR(20) NOT NULL,
    DES_EST  VARCHAR(120)
);

-- Tabla RESPONSABLE
CREATE TABLE RESPONSABLE (
    ID_RESP   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    NOM_RESP  VARCHAR(30) NOT NULL,
    APE_RESP  VARCHAR(30) NOT NULL,
    TIP_RESP  VARCHAR(20) NOT NULL,
    COR_RESP  VARCHAR(60),
    TEL_RESP  VARCHAR(15)
);

-- Tabla ARTICULO
CREATE TABLE ARTICULO (
    ID_ART   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    COD_BAR  VARCHAR(30) UNIQUE,
    COD_INS  VARCHAR(30) UNIQUE,
    NOM_ART  VARCHAR(60) NOT NULL,
    DES_ART  VARCHAR(200),
    MAR_ART  VARCHAR(30),
    MOD_ART  VARCHAR(30),
    SER_ART  VARCHAR(40),
    FEC_REG  DATE NOT NULL,
    IMG_ART  VARCHAR(120),
    ACT_ART  CHAR(1) DEFAULT 'S' NOT NULL,
    ID_CAT   NUMBER(10) NOT NULL,
    ID_EST   NUMBER(10) NOT NULL,
    ID_UBI   NUMBER(10) NOT NULL,
    ID_RESP  NUMBER(10),
    CONSTRAINT FK_ARTICULO_CATEGORIA   FOREIGN KEY (ID_CAT)  REFERENCES CATEGORIA(ID_CAT),
    CONSTRAINT FK_ARTICULO_ESTADO      FOREIGN KEY (ID_EST)  REFERENCES ESTADO_ARTICULO(ID_EST),
    CONSTRAINT FK_ARTICULO_UBICACION   FOREIGN KEY (ID_UBI)  REFERENCES UBICACION(ID_UBI),
    CONSTRAINT FK_ARTICULO_RESPONSABLE FOREIGN KEY (ID_RESP) REFERENCES RESPONSABLE(ID_RESP),
    CONSTRAINT CK_ARTICULO_ACT         CHECK (ACT_ART IN ('S','N'))
);

-- Tabla PRESTAMO
CREATE TABLE PRESTAMO (
    ID_PRE        NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    FEC_PRE       DATE NOT NULL,
    FEC_DEV_PRO   DATE NOT NULL,
    FEC_DEV_REAL  DATE,
    EST_PRE       VARCHAR(20) NOT NULL,
    OBS_PRE       VARCHAR(200),
    ID_USU        NUMBER(10) NOT NULL,
    ID_RESP       NUMBER(10) NOT NULL,
    CONSTRAINT FK_PRESTAMO_USUARIO     FOREIGN KEY (ID_USU)  REFERENCES USUARIO(ID_USU),
    CONSTRAINT FK_PRESTAMO_RESPONSABLE FOREIGN KEY (ID_RESP) REFERENCES RESPONSABLE(ID_RESP)
);

-- Tabla DETALLE_PRESTAMO
CREATE TABLE DETALLE_PRESTAMO (
    ID_DET_PRE   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    ID_PRE       NUMBER(10) NOT NULL,
    ID_ART       NUMBER(10) NOT NULL,
    EST_ENT      VARCHAR(30),
    EST_DEV      VARCHAR(30),
    OBS_DET_PRE  VARCHAR(200),
    CONSTRAINT FK_DETALLE_PRESTAMO_PRESTAMO FOREIGN KEY (ID_PRE) REFERENCES PRESTAMO(ID_PRE),
    CONSTRAINT FK_DETALLE_PRESTAMO_ARTICULO FOREIGN KEY (ID_ART) REFERENCES ARTICULO(ID_ART)
);

-- Tabla MANTENIMIENTO
CREATE TABLE MANTENIMIENTO (
    ID_MAN   NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    TIP_MAN  VARCHAR(20) NOT NULL,
    FEC_INI  DATE NOT NULL,
    FEC_FIN  DATE,
    DES_MAN  VARCHAR(200),
    COS_MAN  DECIMAL(10,2),
    PRO_TEC  VARCHAR(40),
    RES_MAN  VARCHAR(30),
    ID_ART   NUMBER(10) NOT NULL,
    ID_USU   NUMBER(10) NOT NULL,
    CONSTRAINT FK_MANTENIMIENTO_ARTICULO FOREIGN KEY (ID_ART) REFERENCES ARTICULO(ID_ART),
    CONSTRAINT FK_MANTENIMIENTO_USUARIO  FOREIGN KEY (ID_USU) REFERENCES USUARIO(ID_USU)
);

-- Tabla MOVIMIENTO
CREATE TABLE MOVIMIENTO (
    ID_MOV      NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    FEC_MOV     DATE NOT NULL,
    TIP_MOV     VARCHAR(20) NOT NULL,
    DES_MOV     VARCHAR(200),
    ID_UBI_ORI  NUMBER(10),
    ID_UBI_DES  NUMBER(10),
    ID_EST_ANT  NUMBER(10),
    ID_EST_NUE  NUMBER(10),
    ID_ART      NUMBER(10) NOT NULL,
    ID_USU      NUMBER(10) NOT NULL,
    CONSTRAINT FK_MOVIMIENTO_UBI_ORI   FOREIGN KEY (ID_UBI_ORI) REFERENCES UBICACION(ID_UBI),
    CONSTRAINT FK_MOVIMIENTO_UBI_DES   FOREIGN KEY (ID_UBI_DES) REFERENCES UBICACION(ID_UBI),
    CONSTRAINT FK_MOVIMIENTO_EST_ANT   FOREIGN KEY (ID_EST_ANT) REFERENCES ESTADO_ARTICULO(ID_EST),
    CONSTRAINT FK_MOVIMIENTO_EST_NUE   FOREIGN KEY (ID_EST_NUE) REFERENCES ESTADO_ARTICULO(ID_EST),
    CONSTRAINT FK_MOVIMIENTO_ARTICULO  FOREIGN KEY (ID_ART)     REFERENCES ARTICULO(ID_ART),
    CONSTRAINT FK_MOVIMIENTO_USUARIO   FOREIGN KEY (ID_USU)     REFERENCES USUARIO(ID_USU)
);

-- Tabla NOTIFICACION
CREATE TABLE NOTIFICACION (
    ID_NOT       NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    ASU_NOT      VARCHAR(80) NOT NULL,
    MEN_NOT      VARCHAR(300) NOT NULL,
    FEC_GEN      DATE NOT NULL,
    FEC_ENV      DATE,
    EST_NOT      VARCHAR(20) NOT NULL,
    TIP_NOT      VARCHAR(30) NOT NULL,
    ID_PRE       NUMBER(10),
    ID_USU_DEST  NUMBER(10),
    CONSTRAINT FK_NOTIFICACION_PRESTAMO FOREIGN KEY (ID_PRE)      REFERENCES PRESTAMO(ID_PRE),
    CONSTRAINT FK_NOTIFICACION_USUARIO  FOREIGN KEY (ID_USU_DEST) REFERENCES USUARIO(ID_USU)
);

-- Tabla AUDITORIA
CREATE TABLE AUDITORIA (
    ID_AUD      NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    FEC_HOR     TIMESTAMP NOT NULL,
    ACC_AUD     VARCHAR(20) NOT NULL,
    TAB_AUD     VARCHAR(30) NOT NULL,
    ID_REG_AUD  NUMBER(10) NOT NULL,
    DES_AUD     VARCHAR(200),
    IP_EQU      VARCHAR(45),
    ID_USU      NUMBER(10) NOT NULL,
    CONSTRAINT FK_AUDITORIA_USUARIO FOREIGN KEY (ID_USU) REFERENCES USUARIO(ID_USU)
);

COMMIT;
